import React from "react";
import { Bar, Pie, Line } from "react-chartjs-2";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend
);

function Analytics() {

  // KPI DATA
  const totalStudents = 120;
  const placedStudents = 75;
  const placementRate = ((placedStudents / totalStudents) * 100).toFixed(1);
  const avgCGPA = 7.8;

  // BRANCH PLACEMENT BAR
  const branchData = {
    labels: ["CSE", "IT", "EXTC", "Mechanical"],
    datasets: [
      {
        label: "Placed Students",
        data: [40, 25, 18, 10],
        backgroundColor: "#2563eb",
      },
    ],
  };

  // PIE CHART
  const pieData = {
    labels: ["Placed", "Unplaced"],
    datasets: [
      {
        data: [75, 45],
        backgroundColor: ["#22c55e", "#ef4444"],
      },
    ],
  };

  // SKILL VS PLACEMENT
  const skillData = {
    labels: ["50-60", "60-70", "70-80", "80-90", "90+"],
    datasets: [
      {
        label: "Placement %",
        data: [30, 45, 60, 78, 92],
        backgroundColor: "#8b5cf6",
      },
    ],
  };

  // YEARLY TREND
  const trendData = {
    labels: ["2021", "2022", "2023", "2024"],
    datasets: [
      {
        label: "Placement %",
        data: [58, 62, 70, 74],
        borderColor: "#22c55e",
        backgroundColor: "#22c55e",
        tension: 0.4,
      },
    ],
  };

  const options = {
    responsive: true,
    plugins: {
      legend: {
        labels: { color: "white" },
      },
    },
    scales: {
      x: {
        ticks: { color: "white" },
      },
      y: {
        ticks: { color: "white" },
      },
    },
  };

  return (
    <div style={{ padding: "30px", color: "white" }}>

      <h1 style={{ marginBottom: "30px" }}>
        Placement Analytics
      </h1>

      {/* KPI CARDS */}

      <div style={{
        display: "grid",
        gridTemplateColumns: "repeat(4,1fr)",
        gap: "20px",
        marginBottom: "40px"
      }}>

        <div style={cardStyle}>
          <h3>Total Students</h3>
          <p>{totalStudents}</p>
        </div>

        <div style={cardStyle}>
          <h3>Placed Students</h3>
          <p>{placedStudents}</p>
        </div>

        <div style={cardStyle}>
          <h3>Placement Rate</h3>
          <p>{placementRate}%</p>
        </div>

        <div style={cardStyle}>
          <h3>Average CGPA</h3>
          <p>{avgCGPA}</p>
        </div>

      </div>

      {/* ROW 1 */}

      <div style={{
        display: "grid",
        gridTemplateColumns: "1fr 1fr",
        gap: "30px",
        marginBottom: "40px"
      }}>

        <div style={{ width: "100%" }}>
          <Bar data={branchData} options={options} />
        </div>

        <div style={{ width: "350px", margin: "auto" }}>
          <Pie data={pieData} />
        </div>

      </div>

      {/* ROW 2 */}

      <div style={{
        display: "grid",
        gridTemplateColumns: "1fr 1fr",
        gap: "30px"
      }}>

        <div>
          <Bar data={skillData} options={options} />
        </div>

        <div>
          <Line data={trendData} options={options} />
        </div>

      </div>

    </div>
  );
}

const cardStyle = {
  background: "#0f172a",
  padding: "20px",
  borderRadius: "10px",
  textAlign: "center",
  border: "1px solid #1e293b"
};

export default Analytics;
